 }
}];

const raw = $input.first().json;
let from = "", body = "", messageSid = "", mediaUrl = "", numMedia = 0;
if (raw.body && typeof raw.body === "object" && raw.body.From) {
  from = raw.body.From; body = raw.body.Body || ""; messageSid = raw.body.MessageSid || "";
  mediaUrl = raw.body.MediaUrl0 || ""; numMedia = parseInt(raw.body.NumMedia || "0");
} else if (raw.body && typeof raw.body === "string") {
  const params = new URLSearchParams(raw.body);
  from = params.get("From") || ""; body = params.get("Body") || ""; messageSid = params.get("MessageSid") || "";
  mediaUrl = params.get("MediaUrl0") || ""; numMedia = parseInt(params.get("NumMedia") || "0");
} else {
  from = raw.From || raw.from || ""; body = raw.Body || "";
  messageSid = raw.MessageSid || ""; mediaUrl = raw.MediaUrl0 || ""; numMedia = parseInt(raw.NumMedia || "0");
}
if (!from && !body && numMedia === 0) { return []; }
const isWhatsApp = from.startsWith("whatsapp:");
const phone = from.replace(/^whatsapp:/, "").replace(/^\+/, "");
const channel = isWhatsApp ? "whatsapp" : "sms";
return [{ json: { phone, message: body, message_sid: messageSid, channel, media_url: mediaUrl, num_media: numMedia } }];

const chatId = String($('Telegram Trigger').item.json.callback_query.message.chat.id);
const resolved = $('Resolve Ticket').first()?.json;
const ticketId = resolved?.ticket_id || '';
const isFrench = $('Telegram Trigger').item.json.callback_query?.message?.text?.includes('vidéo') || false;

const msg = isFrench
 ? 'Super! Le billet ' + ticketId + ' a été marqué comme résolu. Merci!'
 : 'Great! Ticket ' + ticketId + ' has been marked as resolved. Thank you!';

// Send ack message
await this.helpers.httpRequest({
 method: 'POST',
 url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
 body: { chat_id: chatId, text: msg },
 json: true
});

return [{ json: { chat_id: chatId, ticket_id: ticketId, ack_msg: msg } }];

const chatId = $('Telegram Trigger').item.json.callback_query.message.chat.id;
const isFrench = $('Telegram Trigger').item.json.callback_query?.message?.text?.includes('vidéo') || false;

const msg = isFrench
 ? 'Pas de souci! Quelqu\'un de notre équipe vous contactera bientôt.'
 : 'No worries! Someone from our team will follow up with you soon.';

const result = await this.helpers.httpRequest({
 method: 'POST',
 url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
 body: { chat_id: chatId, text: msg },
 json: true
});
return [{ json: result }];

// AI-powered video matching using Claude Haiku
const videos = $('Search Repair Videos').all().map(v => v.json);

let message = '';
let channel = '';
let chat_id = '';
let phone = '';
let email = '';
let responseText = '';

try {
 const payload = $('Build AI Payload').item.json;
 message = (payload.message || '').trim();
 channel = payload.channel || '';
 chat_id = payload.chat_id || '';
 phone = payload.phone || '';
 email = payload.email || '';
} catch(e) {
 try {
 const merged = $('Merge Tenant + Message').item.json;
 message = (merged.norm_message || '').trim();
 channel = merged.norm_channel || '';
 chat_id = merged.norm_chat_id || '';
 phone = merged.phone || '';
 email = merged.email || '';
 } catch(e2) {}
}

try {
 responseText = $('Call AI Agent').item.json.response_text || '';
} catch(e) {}

if (!message || message.length < 5) return [{ json: { has_video: false } }];

const videoList = videos.map((v, i) => i + ': "' + v.title + '"').join('\n');

let bestVideo = null;
try {
 const response = await this.helpers.httpRequest({
 method: 'POST',
 url: 'https://api.anthropic.com/v1/messages',
 headers: {
 'x-api-key': 'ANTHROPIC_API_KEY_SET_IN_N8N_ENV',
 'anthropic-version': '2023-06-01',
 'content-type': 'application/json'
 },
 body: JSON.stringify({
 model: 'claude-haiku-4-5-20251001',
 max_tokens: 20,
 messages: [{
 role: 'user',
 content: 'The tenant sent this message: "' + message + '"\n\nAvailable repair videos:\n' + videoList + '\n\nRULES:\n- Reply with ONLY a number OR "none"\n- If the tenant\'s message mentions a problem that a video covers, reply with that video\'s number\n- If multiple issues are mentioned, pick the ONE video most likely to help them right now\n- If tenant says "thank you", "ok", "yes", or just confirms something - reply "none"\n- Only reply "none" if truly no video is relevant'
 }]
 }),
 returnFullResponse: false
 });

 const parsed = typeof response === 'string' ? JSON.parse(response) : response;
 const aiAnswer = (parsed.content?.[0]?.text || '').trim().toLowerCase().split(/[\s\n]/)[0];
 if (aiAnswer !== 'none' && !isNaN(parseInt(aiAnswer))) {
 const idx = parseInt(aiAnswer);
 if (idx >= 0 && idx < videos.length) bestVideo = videos[idx];
 }
} catch(e) {
 return [{ json: { has_video: false } }];
}

return [{
 json: {
 has_video: bestVideo !== null,
 video_url: bestVideo?.video_url || '',
 video_title: bestVideo?.title || '',
 channel: channel,
 chat_id: chat_id,
 phone: phone,
 email: email,
 response_text: responseText
 }
}];

const input = $input.first().json;
if (!input.has_video || !input.video_url) return [{ json: { sent: false } }];

const channel = input.channel;
const chat_id = input.chat_id;
const phone = (input.phone || '').replace(/[^0-9]/g, '');
const isFrench = (input.response_text || '').includes('Bonjour') || (input.response_text || '').includes('merci');

const videoMsg = isFrench
  ? 'Cette vidéo pourrait vous aider :\n' + input.video_title + '\n' + input.video_url
  : 'This video might help:\n' + input.video_title + '\n' + input.video_url;

const ticketLookup = input.chat_id || '';

const questionText = isFrench 
  ? 'Est-ce que cette vidéo a aidé à résoudre votre problème?'
  : 'Did this video help resolve your issue?';

try {
  if (channel === 'telegram') {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
      body: { chat_id: chat_id, text: videoMsg },
      json: true
    });
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
      body: {
        chat_id: chat_id,
        text: questionText,
        reply_markup: JSON.stringify({
          inline_keyboard: [[
            { text: isFrench ? 'Oui ✅' : 'Yes ✅', callback_data: 'video_yes||' + ticketLookup },
            { text: isFrench ? 'Non ❌' : 'No ❌', callback_data: 'video_no||' + ticketLookup }
          ]]
        })
      },
      json: true
    });
  } else if (channel === 'whatsapp') {
    // For WhatsApp, just output the video data - a subsequent Execute Workflow node will send it
    return [{ json: { 
      sent: false, 
      needs_wa_send: true,
      video_message: videoMsg,
      question_text: questionText,
      channel, phone, chat_id, ticketLookup, isFrench,
      video_title: input.video_title, video_url: input.video_url
    }}];
  }
} catch(e) {
  console.error('Send Video Followup error:', e.message);
  return [{ json: { sent: false, error: e.message, channel, chat_id } }];
}

return [{ json: { sent: true, channel, video_title: input.video_title, chat_id, video_url: input.video_url } }];

const chatId = $('Telegram Trigger').item.json.callback_query.message.chat.id;
const reopened = $('Reopen Ticket').first()?.json;
const ticketId = reopened?.ticket_id || '';
const isFrench = $('Telegram Trigger').item.json.callback_query?.message?.text?.includes('problème') || false;

const msg = isFrench
 ? 'Merci de nous avoir informé. Le billet ' + ticketId + ' a été réouvert et quelqu\'un vous contactera bientôt.'
 : 'Thank you for letting us know. Ticket ' + ticketId + ' has been reopened and someone will follow up with you shortly.';

await this.helpers.httpRequest({
 method: 'POST',
 url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
 body: { chat_id: String(chatId), text: msg },
 json: true
});

return [{ json: { chat_id: String(chatId), ticket_id: ticketId, ack_msg: msg } }];

// Send typing indicator + check if AI already responded recently (dedup)
const msg = $('Telegram Trigger').item.json.message;
if (!msg || !msg.chat) return [];

const chatId = String(msg.chat.id);

// Send typing indicator immediately
await this.helpers.httpRequest({
 method: 'POST',
 url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendChatAction',
 body: { chat_id: chatId, action: 'typing' },
 json: true
});

return [{ json: { ...$('Telegram Trigger').item.json, typing_sent: true } }];

const merged = $('Merge Tenant + Message').item.json;
const channel = merged.norm_channel;
const chatId = merged.norm_chat_id;
const pendingId = $('Save Pending Media').item.json.id;
const tickets = $('Get Tickets for Media').all().map(i => i.json).filter(t => t.ticket_id);
const shortId = pendingId.slice(-12);

if (channel === 'telegram') {
  const rows = [];

  for (const t of tickets) {
    const kw = t.keywords || t.category?.replace(/_/g, ' ') || 'open ticket';
    const label = t.ticket_id + ' - ' + kw;
    rows.push([{ text: label, callback_data: 'mc||' + t.ticket_id + '||' + shortId }]);
  }

  const messageText = tickets.length > 0
    ? '📸 Photo received! Which ticket is this for?'
    : '📸 Photo received! No open tickets found — please describe the issue first, then send the photo.';

  if (rows.length > 0) {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
      body: {
        chat_id: chatId,
        text: messageText,
        reply_markup: JSON.stringify({ inline_keyboard: rows })
      },
      json: true
    });
  } else {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
      body: { chat_id: chatId, text: messageText },
      json: true
    });
  }
}

return [{ json: { sent: true, pending_id: pendingId, has_tickets: tickets.length > 0 } }];

// Map short category codes OR existing ticket IDs
const callbackData = $('Parse Callback').item.json;
const shortCode = callbackData.ticket_id; // parts[1] = short category code or ticket_id
const shortId = callbackData.category; // parts[2] = last 12 chars of pending_id
const chatId = callbackData.chat_id;

const codeMap = {
  plumb: 'plumbing', elec: 'electrical', hvac: 'hvac',
  maint: 'general_maintenance', pest: 'pest_control', other: 'general_inquiry'
};

// If it starts with TK-, it's an existing ticket ID
const isExistingTicket = shortCode.startsWith('TK-');
const category = isExistingTicket ? shortCode : (codeMap[shortCode] || 'general_inquiry');

return [{
  json: {
    short_id: shortId,
    category: category,
    chat_id: chatId,
    existing_ticket: isExistingTicket,
    ticket_id: isExistingTicket ? shortCode : ''
  }
}];

const chatId = $('Parse Callback').item.json.chat_id;
const category = $json.category || 'unknown';
const isFrench = false; // TODO: detect language

const categoryLabels = {
 plumbing: 'Plumbing', electrical: 'Electrical', hvac: 'Heating/AC',
 general_maintenance: 'General Maintenance', pest_control: 'Pest Control',
 general_inquiry: 'Other'
};

const label = categoryLabels[category] || category;
const msg = 'Got it! Your photo has been logged under **' + label + '**. We\'ll include it with your ticket.';

await this.helpers.httpRequest({
 method: 'POST',
 url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
 body: { chat_id: chatId, text: msg, parse_mode: 'Markdown' },
 json: true
});

return [{ json: { sent: true } }];

const items = $input.all();
const item = items[0];
const binaryKey = Object.keys(item.binary || {})[0];
if (!binaryKey) return [{ json: { saved: false } }];

const binary = item.binary[binaryKey];
const mimeExt = (binary.mimeType || '').split('/').pop() || 'jpg';
const ext = binary.fileExtension || mimeExt;
const filename = Date.now() + '_' + Math.random().toString(36).slice(2,8) + '.' + ext;
const filePath = '/files/media/' + filename;

// Use n8n's built-in binary helper to get the actual buffer
const dataBuffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const fs = require('fs');
fs.writeFileSync(filePath, dataBuffer);

return [{ json: { saved: true, filename, filePath, url: '/api/media/' + filename } }];

const raw = $input.first().json;
let phone = '', message = '', messageId = '', senderName = '';
if (raw.body && typeof raw.body === 'object') {
  phone = (raw.body.phone || '').replace(/^\+/, '');
  message = raw.body.message || '';
  messageId = raw.body.messageId || '';
  senderName = raw.body.senderName || '';
} else if (raw.body && typeof raw.body === 'string') {
  const params = new URLSearchParams(raw.body);
  phone = (params.get('phone') || '').replace(/^\+/, '');
  message = params.get('message') || '';
  messageId = params.get('messageId') || '';
  senderName = params.get('senderName') || '';
} else {
  phone = (raw.phone || '').replace(/^\+/, '');
  message = raw.message || '';
  messageId = raw.messageId || '';
  senderName = raw.senderName || '';
}
if (!phone && !message) { return []; }
return [{ json: { phone, message, message_sid: messageId, channel: 'whatsapp', media_url: '', num_media: 0, sender_name: senderName } }];

const inp = $input.item.json;
const phone = String(inp.phone || '').replace(/^\+/, '');
const msgSid = inp.message_sid || String(Date.now());
return {
  channel: 'whatsapp',
  sender_identifier: phone,
  message: inp.message || '',
  subject: '',
  chat_id: phone,
  has_media: false,
  media_type: '',
  external_message_id: 'wa_' + msgSid + '_' + phone,
  media_id: '',
  media_url: ''
};

const inp = $input.first().json;
return {
  json: {
    response_text: inp.video_message,
    channel: 'whatsapp',
    chat_id: inp.phone,
    phone: inp.phone,
    email: '',
    tenant_name: ''
  }
};

const items = $('Send Video Followup').all();
const data = items[0]?.json || {};
if (!data.needs_wa_send) return [];
const phone = (data.phone || '').replace(/[^0-9]/g, '');
if (!phone) return [];
return [{ json: { phone } }];
